CREATE TABLE IF NOT EXISTS eligibleVoters (
  id INT AUTO_INCREMENT PRIMARY KEY,
  citizenId VARCHAR(9) NOT NULL UNIQUE,
  name VARCHAR(255) NOT NULL,
  email VARCHAR(320),
  isActive BOOLEAN DEFAULT TRUE,
  createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updatedAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);

ALTER TABLE mk121Bills ADD COLUMN IF NOT EXISTS votingStartsAt TIMESTAMP NULL;
ALTER TABLE mk121Bills ADD COLUMN IF NOT EXISTS votingEndsAt TIMESTAMP NULL;

ALTER TABLE mk121Questions ADD COLUMN IF NOT EXISTS votingStartsAt TIMESTAMP NULL;
ALTER TABLE mk121Questions ADD COLUMN IF NOT EXISTS votingEndsAt TIMESTAMP NULL;

